import history from '../history';
import {
  SIGN_IN,
  SIGN_OUT,
  CREATE_ALBUM,
  FETCH_ALBUMS,
  FETCH_ALBUM,
  EDIT_ALBUM,
  DELETE_ALBUM
} from './types';

import albums from '../apis/albums';

// Local storage helpers for fallback
const getLocalAlbums = () => {
  const stored = localStorage.getItem('xsr_albums');
  if (stored) {
    try {
      return JSON.parse(stored);
    } catch (e) {
      console.error(e);
    }
  }
  // Default mock data containing both id and _id for compatibility
  const defaultAlbums = [
    {
      id: 'mock-1',
      _id: 'mock-1',
      albumName: 'After Hours',
      numberOfTracks: '14',
      artist: 'The Weeknd',
      userId: 'mock-user-123'
    },
    {
      id: 'mock-2',
      _id: 'mock-2',
      albumName: 'Random Access Memories',
      numberOfTracks: '13',
      artist: 'Daft Punk',
      userId: 'mock-user-123'
    },
    {
      id: 'mock-3',
      _id: 'mock-3',
      albumName: 'Abbey Road',
      numberOfTracks: '17',
      artist: 'The Beatles',
      userId: 'mock-user-456'
    }
  ];
  localStorage.setItem('xsr_albums', JSON.stringify(defaultAlbums));
  return defaultAlbums;
};

const setLocalAlbums = (list) => {
  localStorage.setItem('xsr_albums', JSON.stringify(list));
};

export const signIn = ( userId ) => {
  return {
    type: SIGN_IN,
    payload: userId
  };
};

export const signOut = () => {
  return {
    type: SIGN_OUT
  };
};

export const createAlbum = formValues => async ( dispatch, getState ) => {
  const { userId } = getState().auth;
  try {
    const response = await albums.post('/albums',{...formValues, userId});
    dispatch({type: CREATE_ALBUM, payload: response.data});
  } catch (error) {
    console.warn("Backend server not running. Falling back to localStorage.", error);
    const mockId = `mock-${Date.now()}`;
    const newAlbum = {
      id: mockId,
      _id: mockId,
      ...formValues,
      userId: userId || 'guest'
    };
    const list = getLocalAlbums();
    list.push(newAlbum);
    setLocalAlbums(list);
    dispatch({type: CREATE_ALBUM, payload: newAlbum});
  }
  history.push('/');
};

export const fetchAlbums = () => async dispatch => {
  try {
    const response = await albums.get('/albums');
    dispatch({type: FETCH_ALBUMS, payload: response.data});
  } catch (error) {
    console.warn("Backend server not running. Falling back to localStorage.", error);
    dispatch({type: FETCH_ALBUMS, payload: getLocalAlbums()});
  }
}

export const fetchAlbum = (id) => async dispatch => {
  try {
    const response = await albums.get(`/albums/${id}`);
    dispatch({type: FETCH_ALBUM, payload: response.data});
  } catch (error) {
    console.warn("Backend server not running. Falling back to localStorage.", error);
    const list = getLocalAlbums();
    const item = list.find(a => a._id === id || a.id === id) || { id: id, _id: id, albumName: 'Unknown', numberOfTracks: 0 };
    dispatch({type: FETCH_ALBUM, payload: item});
  }
}

export const editAlbum = (id, formValues) => async dispatch => {
  try {
    const response = await albums.patch(`/albums/edit/${id}`, formValues);
    dispatch({type: EDIT_ALBUM, payload: response.data});
  } catch (error) {
    console.warn("Backend server not running. Falling back to localStorage.", error);
    const list = getLocalAlbums();
    const updatedList = list.map(a => (a._id === id || a.id === id) ? { ...a, ...formValues } : a);
    setLocalAlbums(updatedList);
    const updated = updatedList.find(a => a._id === id || a.id === id);
    dispatch({type: EDIT_ALBUM, payload: updated});
  }
  history.push('/');
}

export const deleteAlbum = (id) => async dispatch => {
  try {
    await albums.delete(`/albums/${id}`);
    dispatch({type: DELETE_ALBUM, payload: id});
  } catch (error) {
    console.warn("Backend server not running. Falling back to localStorage.", error);
    const list = getLocalAlbums();
    const updatedList = list.filter(a => a._id !== id && a.id !== id);
    setLocalAlbums(updatedList);
    dispatch({type: DELETE_ALBUM, payload: id});
  }
  history.push('/');
}
